const LOGO_COLOR: Record<LogoColour, string> = {
  White: colors.textInverted,
  Black: colors.textHeadingNeutral,
  Colour: semanticColors.backdropSurfaceColouredSurface,
};

function dim(v: number | string | undefined): string | undefined {
  if (v === undefined) return undefined;
  return typeof v === "number" ? `${v}px` : v;
}

